-- Insertion des FAQs
INSERT INTO faqs (id, question, answer, categorie, ordre, actif, created_at, updated_at) VALUES
('1', 'Comment louer un bien ?', 'Pour louer un bien, parcourez nos annonces, sélectionnez le bien qui vous intéresse, puis contactez-nous via le formulaire ou par téléphone. Nous organiserons une visite et vous accompagnerons dans toutes les démarches administratives.', NULL, 1, true, NOW(), NOW()),
('2', 'Quels documents fournir pour une location ?', 'Vous devrez fournir : pièce d''identité, 3 derniers bulletins de salaire, dernier avis d''imposition, justificatif de domicile, RIB. Pour les garants : mêmes documents + attestation de garant.', NULL, 2, true, NOW(), NOW()),
('3', 'Quels sont les frais d''agence ?', 'Les frais d''agence varient selon le type de location. Pour une location annuelle, comptez environ 1 mois de loyer HT. Pour une location saisonnière, les frais sont inclus dans le prix affiché. Contactez-nous pour un devis personnalisé.', NULL, 3, true, NOW(), NOW()),
('4', 'Quelle est la durée du bail ?', 'Pour une location vide, le bail est de 3 ans minimum (6 ans pour les personnes morales). Pour une location meublée, le bail est d''1 an minimum (9 mois pour les étudiants). Les locations saisonnières sont de courte durée (quelques jours à quelques mois).', NULL, 4, true, NOW(), NOW()),
('5', 'Comment fonctionne la caution ?', 'Le dépôt de garantie équivaut généralement à 1 mois de loyer hors charges pour une location vide, et 2 mois pour une location meublée. Il vous sera restitué dans un délai de 1 à 2 mois après votre départ, déduction faite des éventuelles réparations.', NULL, 5, true, NOW(), NOW()),
('6', 'Comment résilier mon bail ?', 'Pour résilier votre bail, envoyez une lettre recommandée avec accusé de réception à votre propriétaire. Le préavis est de 3 mois pour une location vide (1 mois dans certains cas) et 1 mois pour une location meublée.', NULL, 6, true, NOW(), NOW())
ON DUPLICATE KEY UPDATE updated_at = NOW();

-- Insertion de l'article de blog sur Micah Fatna (avec images base64)
-- Note: Les images sont en base64 pour faciliter l'import
INSERT INTO blog_posts (id, slug, title, excerpt, content, cover_image, images, category, tags, author, is_pinned, is_published, views, published_at, created_at, updated_at, cover_image_position, links) VALUES
('1', 'sponsoring-micah-fatna-moto-gp', 'BBF Immobilier sponsorise Micah Fatna, jeune champion de Moto GP', 'Nous sommes fiers d''annoncer notre partenariat avec Micah Fatna, jeune talent martiniquais en Moto GP. Découvrez son parcours exceptionnel et notre engagement pour la jeunesse locale.', '<h2><ol><li><b style="font-family: var(--font-inter), system-ui, sans-serif;">Un talent martiniquais qui fait vibrer les circuits</b></li></ol></h2><div><br></div><p>Chez BBF Immobilier - Bulle Immobilière Business & Foncier, nous croyons fermement au soutien des talents locaux. C''est avec une immense fierté que nous annonçons notre sponsoring de Micah Fatna, jeune prodige martiniquais qui fait sensation dans le monde de la Moto GP.</p><p><br></p><h3>Qui est Micah Fatna ?</h3><p>Micah Fatna est un jeune pilote de moto originaire de Martinique qui s''est rapidement fait un nom dans le monde compétitif de la Moto GP. Avec sa détermination, son talent et sa passion pour la vitesse, Micah représente l''excellence et l''ambition de la jeunesse martiniquaise.</p><h3><br></h3><h3>Pourquoi BBF sponsorise Micah ?</h3><p>Notre engagement va au-delà de l''immobilier. Nous croyons au développement de notre territoire et au soutien de ceux qui portent haut les couleurs de la Martinique. Micah incarne des valeurs qui nous sont chères :</p><h2><ul><li><strong>La détermination</strong> : Atteindre l''excellence demande du travail et de la persévérance</li></ul><ul><li><strong>L''ambition</strong> : Viser toujours plus haut, comme nous le faisons dans l''immobilier</li></ul><ul><li><strong>Le dépassement de soi</strong> : Repousser ses limites pour atteindre ses objectifs</li></ul><ul><li><strong>La fierté locale</strong> : Représenter la Martinique sur la scène internationale&nbsp;</li></ul></h2><h3><br></h3><h3>Ses prochains objectifs</h3><p>Micah prépare activement ses prochaines compétitions avec un objectif clair : se hisser parmi les meilleurs pilotes de sa catégorie. Nous serons là pour le soutenir à chaque étape de son parcours.</p><h3><br></h3><h3>Suivez son parcours</h3><p>Restez connectés pour suivre les performances de Micah et découvrir comment BBF Immobilier contribue au développement des talents martiniquais. Ensemble, construisons l''avenir de notre île !</p><p><br></p><p>🏍️ <strong>Soutenez Micah Fatna</strong></p><p>Suivez ses courses, partagez ses victoires et encouragez ce jeune talent qui fait la fierté de la Martinique !</p>', '/images/blog/micah-fatna-moto-gp.jpg', NULL, 'Sponsoring', NULL, 'BBF Immobilier', false, true, 0, '2026-03-21 16:00:00', '2026-03-21 16:00:00', '2026-03-21 16:00:00', '50% 50%', NULL)
ON DUPLICATE KEY UPDATE updated_at = NOW();

