', 3, 2, '100', 6, '[\"https://bbf-immobilier.com/images/properties/property-1774092225256-1.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-2.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-3.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-4.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-5.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-6.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-7.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-8.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-9.jpeg\",\"https://bbf-immobilier.com/images/properties/property-1774092225256-10.jpeg\",\"...\"]', '[]', '[{"icon":"❄️","name":"Climatisation"},{"icon":"📶","name":"Wifi"},{"icon":"✓","name":"Jacuzzi privatif"},{"icon":"✓","name":"Linge de maison fourni (draps, serviettes, torchons)"},{"icon":"✓","name":"Accès autonome possible"},{"icon":"🍳","name":"Cuisine équipée"},{"icon":"✓","name":"Assistance locale 7j/7 "}]', true, '2026-03-21 11:23:45.256+00', '2026-03-21 17:31:38.433+00', 4, 'https://www.youtube.com/watch?v=JAcX4JsDW90', NULL, 'brouillon', false, '{"exterior": "Extérieur : grande terrasse couverte, jardin, accès à la piscine commune\\nStationnement : place(s) de parking sur site", "interior": "🛏 Composition & confort\\n\\nCapacité : jusqu’à 6 personnes\\nChambres : 3 chambres climatisées avec lits doubles\\nSéjour : spacieux, lumineux, ouvert sur la terrasse\\nCuisine : équipée (réfrigérateur, plaques, micro-ondes, cafetière, vaisselle…)\\nSalles d’eau : 2 salles d’eau à l’italienne\\nWC : 1 indépendant extérieur", "presentation": "Un refuge au cœur de la verdure pour un séjour tout en sérénité\\n\\nNichée à Rivière-Pilote, dans un quartier paisible, la Villa Leonardo vous offre une escapade relaxante au cœur de la nature. Spacieuse, lumineuse et entourée d’un jardin tropical, elle séduit par son atmosphère chaleureuse, son jacuzzi privé et ses équipements pensés pour le confort. Parfaite pour des vacances en famille, entre amis ou pour un moment de ressourcement.\\n"}', '{"title": "Environnement & Quartier", "highlights": ["🌳 Quartier calme", "🏖️ Proche de la plage", "🏪 Commerces à proximité"], "description": "Quartier très calme\\nEn pleine nature, loin du tumulte touristique\\nÀ environ 10 min en voiture de la plage de l’Anse Figuier\\nProche des commodités : supérettes, commerces\\nIdéal pour les amoureux de calme, de verdure et d’authenticité"}', '["Arrivée : 16 H 00 - Départ : 12 h 00","Animal de compagnie non accepté ","Frais de séjour / animal : 0 € pour l’ensemble du séjour (à ajouter à la réservation)"]', '{"deposit": 925, "minStay": 6, "included": [], "cleaningFee": 150, "notIncluded": ["Option ménage : 150 €  (ou nettoyage par le locataire)", "Taxe de séjour : obligatoire selon réglementation en vigueur"], "cancellationPolicy": ""}', NULL, '{"agencyFees": 0, "description": ""}', '{"dpe": null, "law": "Location saisonnière conforme à la loi ALUR et ELAN\\n\\nCe logement est déclaré en meublé de tourisme.\\nConformément à la réglementation en vigueur en Martinique, le DPE‑M est en cours de réalisation. L’étiquette énergie/climat sera communiquée aux locataires avant la remise des clés, si la durée cumulée de location excède 120 jours par an.", "insurance": "Assurance responsabilité civile obligatoire", "reference": "Villa Léonardo"}', '{"type": "custom", "period": "/semaine", "simplePrice": 925, "customPricing": {"prices": [{"label": "Basse saison", "price": 925}, {"label": "Moyenne saison", "price": 950}, {"label": "Haute saison", "price": 1100}], "isPackage": true, "description": "Tarif pour 6 nuitées  / 7 jours (hors options)", "packageDays": 7, "packageNights": 6}, "seasonalPricing": {"lowSeason": 0, "midSeason": 0, "highSeason": 0}}'),
('1774096458331', 'saisonniere', 'Les Sables de l''Anse', 'Les Trois-Îlets, Martinique', '480', '/nuit', 'Escapade relaxante à quelques pas de l''Anse Mitan

